// In the onDrop function, fix the data initialization:
const onDrop = (event) => {
  event.preventDefault();
  setIsDraggingOver(false);
  
  const reactFlowBounds = reactFlowWrapper.current.getBoundingClientRect();
  const data = JSON.parse(event.dataTransfer.getData("application/reactflow"));

  if (!data.nodeType) {
    console.error("No nodeType in drop data");
    return;
  }

  const position = {
    x: event.clientX - reactFlowBounds.left - 40,
    y: event.clientY - reactFlowBounds.top - 20,
  };

  const nodeId = `${data.nodeType}-${Date.now()}`;
  
  // Use the data from drag OR create default
  let nodeData = { ...(data.data || {}) };
  
  // Add default label if not present
  if (!nodeData.label) {
    nodeData.label = data.nodeType.replace('Node', '').replace(/([A-Z])/g, ' $1').trim();
  }

  const newNode = {
    id: nodeId,
    type: data.nodeType,
    position,
    data: nodeData,
    className: data.className || "",
    draggable: true,
  };

  setNodes((nds) => [...nds, newNode]);
};
